const seoMapping = seoMappingData as SeoMappingItem[];

interface PageProps {
  params: Promise<{
    slug: string[];
  }>;
}

export async function generateMetadata({ params }: PageProps): Promise<Metadata> {
  const resolvedParams = await params;
  if (!resolvedParams?.slug) return { title: 'Dreamlab' };

  const slug = resolvedParams.slug;
  const path = `/${slug.join('/')}`;
  const pageData = seoMapping.find((m) => m.source === path || m.source === `${path}/`);

  if (!pageData) {
    return {
      title: 'Page Not Found | Dreamlab',
    };
  }

  return {
    title: pageData._metadata.original_title,
    description: pageData._metadata.original_description || 'Migration in progress...',
    alternates: {
      canonical: `https://dreamlab.id${path}`,
    },
  };
}

export default async function DynamicPage({ params }: PageProps) {
  const resolvedParams = await params;
  if (!resolvedParams?.slug) notFound();

  const slug = resolvedParams.slug;
  const pathStr = `/${slug.join('/')}`;
  const pageData = seoMapping.find((m) => m.source === pathStr || m.source === `${pathStr}/`);

  // Check if this is an article
  const article = articles.find(a => a.slug === pathStr || a.slug === `${pathStr}/`);

  if (article) {
    return (
      <main className="min-h-screen">
        <Header />
        <ArticleTemplate article={article} />
        <Footer />
      </main>
    );
  }

  if (!pageData) {
    notFound();
  }

  // Load audit data to get hero image
  const csvPath = path.join(process.cwd(), 'src', 'data', 'seo-audit-export.csv');
  const fileContent = fs.readFileSync(csvPath, 'utf-8');
  const records = parse(fileContent, { columns: true }) as AuditData[];
  const auditData = records.find((r) => r.slug === pathStr || r.slug === `${pathStr}/`);

  const heroImage = auditData?.hero_image_url;
  const heroFilename = heroImage && !heroImage.startsWith('data:') ? path.basename(new URL(heroImage).pathname) : null;

  return (
    <main className="min-h-screen">
      {/* Hero Banner */}
      <section className="relative w-full h-[300px] md:h-[450px] overflow-hidden bg-gray-900">
        {heroFilename ? (
          <Image 
            src={`/assets/images/${heroFilename}`}
            alt={pageData._metadata.original_h1 || 'Hero Image'}
            fill
            className="object-cover opacity-60"
            priority
          />
        ) : (
          <div className="absolute inset-0 bg-gradient-to-br from-brand to-brand-dark opacity-80" />
        )}
        <div className="absolute inset-0 flex flex-col items-center justify-center text-center px-4">
          <h1 className="text-white text-3xl md:text-5xl font-bold max-w-4xl drop-shadow-xl mb-4">
            {pageData._metadata.original_h1}
          </h1>
          <nav className="flex text-white/80 text-sm space-x-2">
            <span className="hover:text-white cursor-pointer">Home</span>
            <span>/</span>
            <span className="text-white font-semibold">{slug[slug.length - 1].replace(/-/g, ' ')}</span>
          </nav>
        </div>
      </section>

      {/* Migration Notice & Content Placeholder */}
      <section className="py-20 container-custom">
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-12">
          {/* Main Content */}
          <div className="lg:col-span-2 space-y-8">
            <div className="bg-orange-50 border-l-8 border-brand p-8 rounded-r-xl shadow-sm">
              <h2 className="text-2xl font-bold text-gray-800 mb-4">🔧 Migration in Progress</h2>
              <p className="text-gray-700 leading-relaxed">
                Kami sedang memindahkan konten dari website lama kami secara bertahap untuk memberikan pengalaman yang lebih cepat dan modern. 
                Halaman <strong>{pageData.source}</strong> akan segera hadir dengan tampilan baru yang lebih premium.
              </p>
              <div className="mt-6 flex gap-4">
                <a href={`https://dreamlab.id${pathStr}`} target="_blank" className="text-brand font-bold hover:underline">
                  Lihat Versi Lama →
                </a>
              </div>
            </div>

            <div className="prose prose-lg max-w-none text-gray-600">
               <p>
                 Dreamlab Indonesia berkomitmen untuk memberikan solusi maklon kosmetik terbaik. 
                 Mulai dari riset formulasi, pengurusan BPOM, hingga desain kemasan, kami adalah mitra strategis Anda dalam membangun brand kecantikan.
               </p>
               <div className="h-4 bg-gray-100 rounded w-3/4 animate-pulse" />
               <div className="h-4 bg-gray-100 rounded w-1/2 animate-pulse" />
               <div className="h-4 bg-gray-100 rounded w-2/3 animate-pulse" />
            </div>
