export async function generateStaticParams() {
  const mappingParams = seoMapping
    .filter(m => 
      m.source !== '/' && 
      m.source.length < 255 && 
      !m.source.includes(':') && 
      !m.source.includes('%20')
    )
    .map((m) => ({
      slug: m.source.split('/').filter(Boolean),
    }));

  const articleParams = articles
    .filter(a => a.slug && a.slug !== '/')
    .map((article) => ({
      slug: article.slug.split('/').filter(Boolean),
    }));

  // Combine and remove duplicates (by join slug)
  const allParams = [...mappingParams, ...articleParams];
  const uniqueParams = Array.from(new Map(allParams.map(p => [p.slug.join('/'), p])).values());

  return uniqueParams;
}

